  "static/golang/internal/seed/constants.go": "package seed\n\nconst (\n\tMaxNameLength   = 100\n\tDefaultLanguage = LangEnglish\n)\n",
  "static/golang/internal/seed/enums.go": "package seed\n\ntype Language int\n\nconst (\n\tLangEnglish Language = iota\n\tLangSpanish\n\tLangFrench\n)\n\nfunc (l Language) String() string {\n\tswitch l {\n\tcase LangEnglish:\n\t\treturn \"english\"\n\tcase LangSpanish:\n\t\treturn \"spanish\"\n\tcase LangFrench:\n\t\treturn \"french\"\n\tdefault:\n\t\treturn \"unknown\"\n\t}\n}\n",
  "static/golang/internal/seed/errors.go": "package seed\n\nimport \"fmt\"\n\ntype SeedError struct {\n\tField   string\n\tMessage string\n}\n\nfunc (e *SeedError) Error() string {\n\treturn fmt.Sprintf(\"%s: %s\", e.Field, e.Message)\n}\n",
  "static/golang/internal/seed/seed_test.go": "package seed\n\nimport (\n\t\"errors\"\n\t\"strings\"\n\t\"testing\"\n)\n\nfunc TestGreetSuccess(t *testing.T) {\n\ttests := []struct {\n\t\tname         string\n\t\tinputName    string\n\t\tlanguage     Language\n\t\twantGreeting string\n\t}{\n\t\t{name: \"should greet in English\", inputName: \"World\", language: LangEnglish, wantGreeting: \"Hello, World!\"},\n\t\t{name: \"should greet in Spanish\", inputName: \"Mundo\", language: LangSpanish, wantGreeting: \"¡Hola, Mundo!\"},\n\t\t{name: \"should trim whitespace and greet in French\", inputName: \"  Alice  \", language: LangFrench, wantGreeting: \"Bonjour, Alice!\"},\n\t}\n\n\tfor _, tt := range tests {\n\t\tt.Run(tt.name, func(t *testing.T) {\n\t\t\tresult, err := Greet(tt.inputName, tt.language)\n\t\t\tif err != nil {\n\t\t\t\tt.Fatalf(\"Greet returned unexpected error: %v\", err)\n\t\t\t}\n\t\t\tif result.Greeting != tt.wantGreeting {\n\t\t\t\tt.Fatalf(\"Greeting = %q, want %q\", result.Greeting, tt.wantGreeting)\n\t\t\t}\n\t\t\tif result.Language != tt.language {\n\t\t\t\tt.Fatalf(\"Language = %v, want %v\", result.Language, tt.language)\n\t\t\t}\n\t\t})\n\t}\n}\n\nfunc TestGreetValidation(t *testing.T) {\n\ttests := []struct {\n\t\tname      string\n\t\tinputName string\n\t}{\n\t\t{name: \"should reject empty name\", inputName: \"   \"},\n\t\t{name: \"should reject name exceeding max length\", inputName: strings.Repeat(\"a\", MaxNameLength+1)},\n\t}\n\n\tfor _, tt := range tests {\n\t\tt.Run(tt.name, func(t *testing.T) {\n\t\t\t_, err := Greet(tt.inputName, LangEnglish)\n\t\t\tvar seedErr *SeedError\n\t\t\tif !errors.As(err, &seedErr) {\n\t\t\t\tt.Fatalf(\"error = %v, want SeedError\", err)\n\t\t\t}\n\t\t\tif seedErr.Field != \"name\" {\n\t\t\t\tt.Fatalf(\"Field = %q, want name\", seedErr.Field)\n\t\t\t}\n\t\t})\n\t}\n}\n",
  "static/golang/internal/seed/seed.go": "package seed\n\nimport (\n\t\"fmt\"\n\t\"log/slog\"\n\t\"strings\"\n)\n\nfunc Greet(name string, lang Language) (SeedResult, error) {\n\ttrimmedName := strings.TrimSpace(name)\n\tif trimmedName == \"\" {\n\t\treturn SeedResult{}, &SeedError{\n\t\t\tField:   \"name\",\n\t\t\tMessage: \"name is required\",\n\t\t}\n\t}\n\n\tif len(trimmedName) > MaxNameLength {\n\t\treturn SeedResult{}, &SeedError{\n\t\t\tField:   \"name\",\n\t\t\tMessage: fmt.Sprintf(\"name exceeds maximum length of %d\", MaxNameLength),\n\t\t}\n\t}\n\n\tgreeting := formatGreeting(trimmedName, lang)\n\tslog.Info(\"greeting generated\", \"name\", trimmedName, \"language\", lang.String())\n\n\treturn SeedResult{\n\t\tGreeting: greeting,\n\t\tLanguage: lang,\n\t}, nil\n}\n\nfunc formatGreeting(name string, lang Language) string {\n\tswitch lang {\n\tcase LangEnglish:\n\t\treturn fmt.Sprintf(\"Hello, %s!\", name)\n\tcase LangSpanish:\n\t\treturn fmt.Sprintf(\"¡Hola, %s!\", name)\n\tcase LangFrench:\n\t\treturn fmt.Sprintf(\"Bonjour, %s!\", name)\n\tdefault:\n\t\treturn fmt.Sprintf(\"Hello, %s!\", name)\n\t}\n}\n",
  "static/golang/internal/seed/types.go": "package seed\n\ntype SeedResult struct {\n\tGreeting string\n\tLanguage Language\n}\n",
  "static/golang/tools/go-analyzers/anti_slop/noerrorobscuring/analyzer_test.go": "package noerrorobscuring_test\n\nimport (\n\t\"testing\"\n\n\t\"golang.org/x/tools/go/analysis/analysistest\"\n\t\"tools/go-analyzers/anti_slop/noerrorobscuring\"\n)\n\nfunc TestAnalyzer(t *testing.T) {\n\tanalysistest.Run(t, analysistest.TestData(), noerrorobscuring.Analyzer, \"noerrorobscuring\")\n}\n",
  "static/golang/tools/go-analyzers/anti_slop/noerrorobscuring/analyzer.go": "package noerrorobscuring\n\nimport (\n\t\"go/ast\"\n\t\"go/types\"\n\n\t\"golang.org/x/tools/go/analysis\"\n\t\"tools/go-analyzers/internal/analyzerutil\"\n)\n\nvar Analyzer = &analysis.Analyzer{Name: \"noerrorobscuring\", Doc: \"reports error paths that discard the checked error\", Run: run}\n\nfunc run(pass *analysis.Pass) (interface{}, error) {\n\tfor _, file := range pass.Files {\n\t\tast.Inspect(file, func(n ast.Node) bool {\n\t\t\tfn, ok := n.(*ast.FuncDecl)\n\t\t\tif !ok || fn.Body == nil || !funcReturnsError(pass, fn) {\n\t\t\t\treturn true\n\t\t\t}\n\t\t\tast.Inspect(fn.Body, func(child ast.Node) bool {\n\t\t\t\tstmt, ok := child.(*ast.IfStmt)\n\t\t\t\tif !ok || stmt.Body == nil || !analyzerutil.IsErrorNilCheck(pass, stmt.Cond) {\n\t\t\t\t\treturn true\n\t\t\t\t}\n\t\t\t\terrorNames := checkedErrorNames(pass, stmt.Cond)\n\t\t\t\tfor _, bodyStmt := range stmt.Body.List {\n\t\t\t\t\tret, ok := bodyStmt.(*ast.ReturnStmt)\n\t\t\t\t\tif !ok {\n\t\t\t\t\t\tcontinue\n\t\t\t\t\t}\n\t\t\t\t\tif !returnContainsCheckedError(ret, errorNames) {\n\t\t\t\t\t\tpass.Reportf(ret.Pos(), \"error path returns without propagating the checked error\")\n\t\t\t\t\t}\n\t\t\t\t}\n\t\t\t\treturn true\n\t\t\t})\n\t\t\treturn false\n\t\t})\n\t}\n\treturn nil, nil\n}\n\nfunc funcReturnsError(pass *analysis.Pass, fn *ast.FuncDecl) bool {\n\tobj := pass.TypesInfo.Defs[fn.Name]\n\tif obj == nil {\n\t\treturn false\n\t}\n\tsig, ok := obj.Type().(*types.Signature)\n\tif !ok {\n\t\treturn false\n\t}\n\tresults := sig.Results()\n\tfor i := 0; i < results.Len(); i++ {\n\t\tif analyzerutil.IsErrorType(results.At(i).Type()) {\n\t\t\treturn true\n\t\t}\n\t}\n\treturn false\n}\n\nfunc checkedErrorNames(pass *analysis.Pass, expr ast.Expr) map[string]bool {\n\tnames := map[string]bool{}\n\tast.Inspect(expr, func(n ast.Node) bool {\n\t\tident, ok := n.(*ast.Ident)\n\t\tif ok && analyzerutil.ExprIsError(pass, ident) {\n\t\t\tnames[ident.Name] = true\n\t\t}\n\t\treturn true\n\t})\n\treturn names\n}\n\nfunc returnContainsCheckedError(ret *ast.ReturnStmt, names map[string]bool) bool {\n\tfound := false\n\tfor _, result := range ret.Results {\n\t\tast.Inspect(result, func(n ast.Node) bool {\n\t\t\tif found || n == nil {\n\t\t\t\treturn !found\n\t\t\t}\n\t\t\tident, ok := n.(*ast.Ident)\n\t\t\tif ok && names[ident.Name] {\n\t\t\t\tfound = true\n\t\t\t\treturn false\n\t\t\t}\n\t\t\treturn true\n\t\t})\n\t}\n\treturn found\n}\n",
  "static/golang/tools/go-analyzers/anti_slop/noerrorobscuring/testdata/src/noerrorobscuring/noerrorobscuring.go": "package noerrorobscuring\n\nimport (\n\t\"errors\"\n\t\"fmt\"\n)\n\nfunc work() error { return errors.New(\"boom\") }\n\nfunc InvalidNil() error {\n\tif e := work(); e != nil {\n\t\treturn nil // want \"without propagating\"\n\t}\n\treturn nil\n}\n\nfunc InvalidDefault() (int, error) {\n\tif problem := work(); problem != nil {\n\t\treturn 0, nil // want \"without propagating\"\n\t}\n\treturn 1, nil\n}\n\nfunc InvalidGeneric() error {\n\tif e := work(); e != nil {\n\t\treturn errors.New(\"failed\") // want \"without propagating\"\n\t}\n\treturn nil\n}\n\nfunc ValidReturn() error {\n\tif e := work(); e != nil {\n\t\treturn e\n\t}\n\treturn nil\n}\n\nfunc ValidWrap() error {\n\tif e := work(); e != nil {\n\t\treturn fmt.Errorf(\"wrapped: %w\", e)\n\t}\n\treturn nil\n}\n\nfunc ValidNoErrorReturn() int {\n\tif e := work(); e != nil {\n\t\treturn 0\n\t}\n\treturn 1\n}\n",
