  "static/golang/tools/go-analyzers/anti_slop/nologcontinue/analyzer.go": "package nologcontinue\n\nimport (\n\t\"go/ast\"\n\n\t\"golang.org/x/tools/go/analysis\"\n\t\"tools/go-analyzers/internal/analyzerutil\"\n)\n\nvar Analyzer = &analysis.Analyzer{Name: \"nologcontinue\", Doc: \"reports error checks that only log and then continue\", Run: run}\n\nfunc run(pass *analysis.Pass) (interface{}, error) {\n\tfor _, file := range pass.Files {\n\t\tast.Inspect(file, func(n ast.Node) bool {\n\t\t\tstmt, ok := n.(*ast.IfStmt)\n\t\t\tif !ok || stmt.Body == nil || !analyzerutil.IsErrorNilCheck(pass, stmt.Cond) {\n\t\t\t\treturn true\n\t\t\t}\n\t\t\tif len(stmt.Body.List) == 0 {\n\t\t\t\treturn true\n\t\t\t}\n\t\t\tfor _, child := range stmt.Body.List {\n\t\t\t\texprStmt, ok := child.(*ast.ExprStmt)\n\t\t\t\tif !ok || !analyzerutil.IsExprLogCall(pass, exprStmt.X) {\n\t\t\t\t\treturn true\n\t\t\t\t}\n\t\t\t}\n\t\t\tpass.Reportf(stmt.Pos(), \"error check only logs and continues; handle or return the error\")\n\t\t\treturn true\n\t\t})\n\t}\n\treturn nil, nil\n}\n",
  "static/golang/tools/go-analyzers/anti_slop/nologcontinue/testdata/src/nologcontinue/nologcontinue.go": "package nologcontinue\n\nimport (\n\t\"errors\"\n\t\"log\"\n)\n\nfunc work() error { return errors.New(\"boom\") }\n\nfunc InvalidErrName() {\n\tif problem := work(); problem != nil { // want \"error check only logs\"\n\t\tlog.Printf(\"failed: %v\", problem)\n\t}\n}\n\nfunc InvalidMultipleLogs() {\n\tif e := work(); e != nil { // want \"error check only logs\"\n\t\tlog.Println(e)\n\t\tlog.Printf(\"again: %v\", e)\n\t}\n}\n\nfunc InvalidCustomLogger(logger interface{ Error(string, ...any) }) {\n\tif e := work(); e != nil { // want \"error check only logs\"\n\t\tlogger.Error(\"failed\", e)\n\t}\n}\n\nfunc ValidReturn() error {\n\tif e := work(); e != nil {\n\t\treturn e\n\t}\n\treturn nil\n}\n\nfunc ValidRecovery() {\n\tif e := work(); e != nil {\n\t\tlog.Print(e)\n\t\trecoverNow()\n\t}\n}\n\nfunc ValidNonError(ok bool) {\n\tif ok != false {\n\t\tlog.Print(\"ok\")\n\t}\n}\n\nfunc recoverNow() {}\n",
