  "static/golang/tools/go-analyzers/anti_slop/nologthrow/analyzer.go": "package nologthrow\n\nimport (\n\t\"go/ast\"\n\n\t\"golang.org/x/tools/go/analysis\"\n\t\"tools/go-analyzers/internal/analyzerutil\"\n)\n\nvar Analyzer = &analysis.Analyzer{Name: \"nologthrow\", Doc: \"reports logging an error and returning it from the same block\", Run: run}\n\nfunc run(pass *analysis.Pass) (interface{}, error) {\n\tfor _, file := range pass.Files {\n\t\tast.Inspect(file, func(n ast.Node) bool {\n\t\t\tstmt, ok := n.(*ast.IfStmt)\n\t\t\tif !ok || stmt.Body == nil || !analyzerutil.IsErrorNilCheck(pass, stmt.Cond) {\n\t\t\t\treturn true\n\t\t\t}\n\t\t\tlogged := false\n\t\t\treturned := false\n\t\t\tast.Inspect(stmt.Body, func(child ast.Node) bool {\n\t\t\t\tswitch node := child.(type) {\n\t\t\t\tcase *ast.CallExpr:\n\t\t\t\t\tif analyzerutil.IsWarnErrorFatalLogCall(pass, node) {\n\t\t\t\t\t\tlogged = true\n\t\t\t\t\t}\n\t\t\t\tcase *ast.ReturnStmt:\n\t\t\t\t\tif analyzerutil.ReturnHasError(pass, node) {\n\t\t\t\t\t\treturned = true\n\t\t\t\t\t}\n\t\t\t\t}\n\t\t\t\treturn true\n\t\t\t})\n\t\t\tif logged && returned {\n\t\t\t\tpass.Reportf(stmt.Pos(), \"error is logged and returned; choose one reporting boundary\")\n\t\t\t}\n\t\t\treturn true\n\t\t})\n\t}\n\treturn nil, nil\n}\n",
  "static/golang/tools/go-analyzers/anti_slop/nologthrow/testdata/src/nologthrow/nologthrow.go": "package nologthrow\n\nimport \"errors\"\n\ntype logger struct{}\n\nfunc (logger) Error(string, ...any) {}\nfunc (logger) Warn(string, ...any)  {}\nfunc (logger) Debug(string, ...any) {}\n\nfunc work() error { return errors.New(\"boom\") }\n\nfunc InvalidError(l logger) error {\n\tif e := work(); e != nil { // want \"logged and returned\"\n\t\tl.Error(\"failed\", e)\n\t\treturn e\n\t}\n\treturn nil\n}\n\nfunc InvalidWarn(l logger) error {\n\tif problem := work(); problem != nil { // want \"logged and returned\"\n\t\tl.Warn(\"failed\", problem)\n\t\treturn problem\n\t}\n\treturn nil\n}\n\nfunc InvalidWrapped(l logger) error {\n\tif e := work(); e != nil { // want \"logged and returned\"\n\t\tl.Error(\"failed\", e)\n\t\treturn wrap(e)\n\t}\n\treturn nil\n}\n\nfunc ValidDebug(l logger) error {\n\tif e := work(); e != nil {\n\t\tl.Debug(\"failed\", e)\n\t\treturn e\n\t}\n\treturn nil\n}\n\nfunc ValidLogOnly(l logger) {\n\tif e := work(); e != nil {\n\t\tl.Error(\"failed\", e)\n\t}\n}\n\nfunc ValidReturnOnly() error {\n\tif e := work(); e != nil {\n\t\treturn e\n\t}\n\treturn nil\n}\n\nfunc wrap(e error) error { return e }\n",
