  "static/golang/tools/go-analyzers/anti_slop/nopassthrough/analyzer.go": "package nopassthrough\n\nimport (\n\t\"go/ast\"\n\n\t\"golang.org/x/tools/go/analysis\"\n)\n\nvar Analyzer = &analysis.Analyzer{Name: \"nopassthrough\", Doc: \"reports pass-through wrappers that only return another call with identical args\", Run: run}\n\nfunc run(pass *analysis.Pass) (interface{}, error) {\n\tfor _, file := range pass.Files {\n\t\tfor _, decl := range file.Decls {\n\t\t\tfn, ok := decl.(*ast.FuncDecl)\n\t\t\tif !ok || fn.Recv != nil || fn.Body == nil || fn.Type.Params == nil || len(fn.Body.List) != 1 {\n\t\t\t\tcontinue\n\t\t\t}\n\t\t\tparams := paramNames(fn.Type.Params)\n\t\t\tif len(params) == 0 {\n\t\t\t\tcontinue\n\t\t\t}\n\t\t\tret, ok := fn.Body.List[0].(*ast.ReturnStmt)\n\t\t\tif !ok || len(ret.Results) != 1 {\n\t\t\t\tcontinue\n\t\t\t}\n\t\t\tcall, ok := ret.Results[0].(*ast.CallExpr)\n\t\t\tif !ok || len(call.Args) != len(params) || isBuiltin(call.Fun) {\n\t\t\t\tcontinue\n\t\t\t}\n\t\t\tsame := true\n\t\t\tfor i, arg := range call.Args {\n\t\t\t\tident, ok := arg.(*ast.Ident)\n\t\t\t\tif !ok || ident.Name != params[i] {\n\t\t\t\t\tsame = false\n\t\t\t\t\tbreak\n\t\t\t\t}\n\t\t\t}\n\t\t\tif same {\n\t\t\t\tpass.Reportf(fn.Pos(), \"pass-through wrapper adds no behavior\")\n\t\t\t}\n\t\t}\n\t}\n\treturn nil, nil\n}\n\nfunc paramNames(fields *ast.FieldList) []string {\n\tvar names []string\n\tfor _, field := range fields.List {\n\t\tfor _, name := range field.Names {\n\t\t\tnames = append(names, name.Name)\n\t\t}\n\t}\n\treturn names\n}\n\nfunc isBuiltin(expr ast.Expr) bool {\n\tident, ok := expr.(*ast.Ident)\n\tif !ok {\n\t\treturn false\n\t}\n\tswitch ident.Name {\n\tcase \"append\", \"cap\", \"clear\", \"close\", \"complex\", \"copy\", \"delete\", \"imag\", \"len\", \"make\", \"max\", \"min\", \"new\", \"panic\", \"print\", \"println\", \"real\", \"recover\":\n\t\treturn true\n\tdefault:\n\t\treturn false\n\t}\n}\n",
  "static/golang/tools/go-analyzers/anti_slop/nopassthrough/testdata/src/nopassthrough/nopassthrough.go": "package nopassthrough\n\nfunc target(a int, b string) int { return a }\n\nfunc Invalid(a int, b string) int { // want \"pass-through wrapper\"\n\treturn target(a, b)\n}\n\nfunc InvalidTwo(a int, b string) int { // want \"pass-through wrapper\"\n\treturn target(a, b)\n}\n\nfunc InvalidThree(a int, b string, c bool) int { // want \"pass-through wrapper\"\n\treturn targetThree(a, b, c)\n}\n\nfunc ValidNoParams() int {\n\treturn target(1, \"x\")\n}\n\nfunc ValidReordered(a int, b string) int {\n\treturn target(btoi(b), itos(a))\n}\n\nfunc ValidAddsBehavior(a int, b string) int {\n\tc := a + 1\n\treturn target(c, b)\n}\n\ntype adapter struct{}\n\nfunc (adapter) ValidMethod(a int, b string) int {\n\treturn target(a, b)\n}\n\nfunc targetThree(a int, b string, c bool) int { return a }\nfunc btoi(s string) int                       { return len(s) }\nfunc itos(i int) string                       { return \"\" }\n",
