  "static/golang/tools/go-analyzers/structural/filelength/analyzer_test.go": "package filelength_test\n\nimport (\n\t\"testing\"\n\n\t\"golang.org/x/tools/go/analysis/analysistest\"\n\t\"tools/go-analyzers/structural/filelength\"\n)\n\nfunc TestAnalyzer(t *testing.T) {\n\tif err := filelength.Analyzer.Flags.Set(\"max-lines\", \"8\"); err != nil {\n\t\tt.Fatal(err)\n\t}\n\tanalysistest.Run(t, analysistest.TestData(), filelength.Analyzer, \"filelength\")\n}\n",
  "static/golang/tools/go-analyzers/structural/filelength/analyzer.go": "package filelength\n\nimport (\n\t\"bytes\"\n\n\t\"golang.org/x/tools/go/analysis\"\n)\n\nvar maxLines int\n\nvar Analyzer = &analysis.Analyzer{Name: \"filelength\", Doc: \"reports files exceeding the configured line threshold\", Run: run}\n\nfunc init() {\n\tAnalyzer.Flags.IntVar(&maxLines, \"max-lines\", 500, \"maximum physical lines per file\")\n}\n\nfunc run(pass *analysis.Pass) (interface{}, error) {\n\tfor _, file := range pass.Files {\n\t\tf := pass.Fset.File(file.Pos())\n\t\tif f == nil {\n\t\t\tcontinue\n\t\t}\n\t\tcontent, err := pass.ReadFile(f.Name())\n\t\tif err != nil {\n\t\t\treturn nil, err\n\t\t}\n\t\tlines := bytes.Count(content, []byte(\"\\n\"))\n\t\tif len(content) > 0 && content[len(content)-1] != '\\n' {\n\t\t\tlines++\n\t\t}\n\t\tif lines > maxLines {\n\t\t\tpass.Reportf(file.Package, \"file has %d lines, exceeding max-lines=%d\", lines, maxLines)\n\t\t}\n\t}\n\treturn nil, nil\n}\n",
