  "static/golang/tools/go-analyzers/test_quality/nodisabledtest/analyzer.go": "package nodisabledtest\n\nimport (\n\t\"go/ast\"\n\t\"strings\"\n\n\t\"golang.org/x/tools/go/analysis\"\n\t\"tools/go-analyzers/internal/analyzerutil\"\n)\n\nvar Analyzer = &analysis.Analyzer{Name: \"nodisabledtest\", Doc: \"reports t.Skip calls without an explanation\", Run: run}\n\nfunc run(pass *analysis.Pass) (interface{}, error) {\n\tfor _, file := range pass.Files {\n\t\tfor _, decl := range file.Decls {\n\t\t\tfn, ok := decl.(*ast.FuncDecl)\n\t\t\tif !ok || fn.Body == nil || !strings.HasPrefix(fn.Name.Name, \"Test\") {\n\t\t\t\tcontinue\n\t\t\t}\n\t\t\tast.Inspect(fn.Body, func(n ast.Node) bool {\n\t\t\t\tcall, ok := n.(*ast.CallExpr)\n\t\t\t\tif !ok {\n\t\t\t\t\treturn true\n\t\t\t\t}\n\t\t\t\tsel, ok := call.Fun.(*ast.SelectorExpr)\n\t\t\t\tif !ok {\n\t\t\t\t\treturn true\n\t\t\t\t}\n\t\t\t\tif sel.Sel.Name != \"Skip\" && sel.Sel.Name != \"Skipf\" && sel.Sel.Name != \"SkipNow\" {\n\t\t\t\t\treturn true\n\t\t\t\t}\n\t\t\t\tif len(call.Args) == 0 {\n\t\t\t\t\tpass.Reportf(call.Pos(), \"disabled test needs an explanation\")\n\t\t\t\t\treturn true\n\t\t\t\t}\n\t\t\t\tif value, ok := analyzerutil.LiteralValue(call.Args[0]); ok && strings.TrimSpace(value) == \"\" {\n\t\t\t\t\tpass.Reportf(call.Pos(), \"disabled test needs an explanation\")\n\t\t\t\t}\n\t\t\t\treturn true\n\t\t\t})\n\t\t}\n\t}\n\treturn nil, nil\n}\n",
  "static/golang/tools/go-analyzers/test_quality/nodisabledtest/testdata/src/nodisabledtest/nodisabledtest_test.go": "package nodisabledtest\n\nimport \"testing\"\n\nfunc TestInvalidSkip(t *testing.T) {\n\tt.Skip() // want \"needs an explanation\"\n}\n\nfunc TestInvalidSkipf(t *testing.T) {\n\tt.Skipf(\"\") // want \"needs an explanation\"\n}\n\nfunc TestInvalidSkipNow(t *testing.T) {\n\tt.SkipNow() // want \"needs an explanation\"\n}\n\nfunc TestValidReason(t *testing.T) {\n\tt.Skip(\"external service unavailable\")\n}\n\nfunc TestValidSkipfReason(t *testing.T) {\n\tt.Skipf(\"waiting on %s\", \"fixture\")\n}\n\nfunc TestValidNoSkip(t *testing.T) {}\n",
