  "static/golang/tools/go-analyzers/test_quality/notautological/analyzer.go": "package notautological\n\nimport (\n\t\"go/ast\"\n\n\t\"golang.org/x/tools/go/analysis\"\n\t\"tools/go-analyzers/internal/analyzerutil\"\n)\n\nvar Analyzer = &analysis.Analyzer{Name: \"notautological\", Doc: \"reports tautological assertions\", Run: run}\n\nfunc run(pass *analysis.Pass) (interface{}, error) {\n\tfor _, file := range pass.Files {\n\t\tast.Inspect(file, func(n ast.Node) bool {\n\t\t\tcall, ok := n.(*ast.CallExpr)\n\t\t\tif !ok {\n\t\t\t\treturn true\n\t\t\t}\n\t\t\tsel, ok := call.Fun.(*ast.SelectorExpr)\n\t\t\tif !ok {\n\t\t\t\treturn true\n\t\t\t}\n\t\t\tif ident, ok := sel.X.(*ast.Ident); ok && (ident.Name == \"assert\" || ident.Name == \"require\") {\n\t\t\t\tswitch sel.Sel.Name {\n\t\t\t\tcase \"Equal\", \"EqualValues\", \"Exactly\":\n\t\t\t\t\tif len(call.Args) >= 3 && sameLiteral(call.Args[1], call.Args[2]) {\n\t\t\t\t\t\tpass.Reportf(call.Pos(), \"assertion compares identical literal values\")\n\t\t\t\t\t}\n\t\t\t\tcase \"True\":\n\t\t\t\t\tif len(call.Args) >= 2 && literal(call.Args[1], \"true\") {\n\t\t\t\t\t\tpass.Reportf(call.Pos(), \"assertion is tautologically true\")\n\t\t\t\t\t}\n\t\t\t\tcase \"False\":\n\t\t\t\t\tif len(call.Args) >= 2 && literal(call.Args[1], \"false\") {\n\t\t\t\t\t\tpass.Reportf(call.Pos(), \"assertion is tautologically false\")\n\t\t\t\t\t}\n\t\t\t\tcase \"Nil\":\n\t\t\t\t\tif len(call.Args) >= 2 && literal(call.Args[1], \"nil\") {\n\t\t\t\t\t\tpass.Reportf(call.Pos(), \"nil assertion on nil is tautological\")\n\t\t\t\t\t}\n\t\t\t\t}\n\t\t\t}\n\t\t\treturn true\n\t\t})\n\t}\n\treturn nil, nil\n}\n\nfunc sameLiteral(a, b ast.Expr) bool {\n\tav, aok := analyzerutil.LiteralValue(a)\n\tbv, bok := analyzerutil.LiteralValue(b)\n\treturn aok && bok && av == bv\n}\nfunc literal(expr ast.Expr, want string) bool {\n\tgot, ok := analyzerutil.LiteralValue(expr)\n\treturn ok && got == want\n}\n",
  "static/golang/tools/go-analyzers/test_quality/notautological/testdata/src/notautological/notautological_test.go": "package notautological\n\nimport \"testing\"\n\ntype assertions struct{}\n\nfunc (assertions) Equal(...any) {}\nfunc (assertions) True(...any)  {}\nfunc (assertions) False(...any) {}\nfunc (assertions) Nil(...any)   {}\n\nvar assert assertions\nvar require assertions\n\nfunc TestInvalidEqual(t *testing.T) {\n\tassert.Equal(t, 1, 1) // want \"identical literal\"\n}\n\nfunc TestInvalidTrue(t *testing.T) {\n\trequire.True(t, true) // want \"tautologically true\"\n}\n\nfunc TestInvalidNil(t *testing.T) {\n\tassert.Nil(t, nil) // want \"nil assertion\"\n}\n\nfunc TestValidEqual(t *testing.T) {\n\tassert.Equal(t, 1, 2)\n}\n\nfunc TestValidVariable(t *testing.T) {\n\tgot := true\n\trequire.True(t, got)\n}\n\nfunc TestValidNilVariable(t *testing.T) {\n\tvar got any\n\tassert.Nil(t, got)\n}\n",
  "static/golang/tools/go-analyzers/test_quality/requireerrortest/analyzer_test.go": "package requireerrortest_test\n\nimport (\n\t\"testing\"\n\n\t\"golang.org/x/tools/go/analysis/analysistest\"\n\t\"tools/go-analyzers/test_quality/requireerrortest\"\n)\n\nfunc TestAnalyzer(t *testing.T) {\n\tanalysistest.Run(t, analysistest.TestData(), requireerrortest.Analyzer, \"requireerrortest\")\n}\n",
  "static/golang/tools/go-analyzers/test_quality/requireerrortest/analyzer.go": "package requireerrortest\n\nimport (\n\t\"go/ast\"\n\t\"go/parser\"\n\t\"go/token\"\n\t\"os\"\n\t\"strings\"\n\n\t\"golang.org/x/tools/go/analysis\"\n\t\"tools/go-analyzers/internal/analyzerutil\"\n)\n\nvar Analyzer = &analysis.Analyzer{Name: \"requireerrortest\", Doc: \"reports error-handling source files without error-path tests\", Run: run}\n\nfunc run(pass *analysis.Pass) (interface{}, error) {\n\tfor _, file := range pass.Files {\n\t\tpath := analyzerutil.FileName(pass, file)\n\t\tif analyzerutil.IsTestFile(path) || !hasErrorHandling(pass, file) {\n\t\t\tcontinue\n\t\t}\n\t\ttest := correspondingTestFile(pass, path)\n\t\tif test == nil {\n\t\t\tparsedTest, err := parseExistingTestFile(pass, strings.TrimSuffix(path, \".go\")+\"_test.go\")\n\t\t\tif err != nil {\n\t\t\t\tcontinue\n\t\t\t}\n\t\t\ttest = parsedTest\n\t\t}\n\t\tif !hasErrorAssertion(pass, test) {\n\t\t\tpass.Reportf(file.Package, \"source file with error handling needs a corresponding error-path test\")\n\t\t}\n\t}\n\treturn nil, nil\n}\n\nfunc hasErrorHandling(pass *analysis.Pass, file *ast.File) bool {\n\tfound := false\n\tast.Inspect(file, func(n ast.Node) bool {\n\t\tif found || n == nil {\n\t\t\treturn !found\n\t\t}\n\t\tif stmt, ok := n.(*ast.IfStmt); ok && analyzerutil.IsErrorNilCheck(pass, stmt.Cond) {\n\t\t\tfound = true\n\t\t\treturn false\n\t\t}\n\t\treturn true\n\t})\n\treturn found\n}\n\nfunc hasErrorAssertion(pass *analysis.Pass, file *ast.File) bool {\n\tfound := false\n\tast.Inspect(file, func(n ast.Node) bool {\n\t\tif found || n == nil {\n\t\t\treturn !found\n\t\t}\n\t\tswitch node := n.(type) {\n\t\tcase *ast.IfStmt:\n\t\t\tif analyzerutil.IsErrorNilCheck(pass, node.Cond) || isErrNilCheck(node.Cond) {\n\t\t\t\tfound = true\n\t\t\t\treturn false\n\t\t\t}\n\t\tcase *ast.CallExpr:\n\t\t\tsel, ok := node.Fun.(*ast.SelectorExpr)\n\t\t\tif !ok {\n\t\t\t\treturn true\n\t\t\t}\n\t\t\tif ident, ok := sel.X.(*ast.Ident); ok && (ident.Name == \"assert\" || ident.Name == \"require\") {\n\t\t\t\tswitch sel.Sel.Name {\n\t\t\t\tcase \"Error\", \"ErrorIs\", \"ErrorAs\", \"EqualError\", \"NotNil\":\n\t\t\t\t\tfound = true\n\t\t\t\t\treturn false\n\t\t\t\t}\n\t\t\t}\n\t\t}\n\t\treturn true\n\t})\n\treturn found\n}\n\nfunc correspondingTestFile(pass *analysis.Pass, sourcePath string) *ast.File {\n\ttestPath := strings.TrimSuffix(sourcePath, \".go\") + \"_test.go\"\n\tfor _, file := range pass.Files {\n\t\tif analyzerutil.FileName(pass, file) == testPath {\n\t\t\treturn file\n\t\t}\n\t}\n\treturn nil\n}\n\nfunc parseExistingTestFile(pass *analysis.Pass, path string) (*ast.File, error) {\n\tcontent, err := os.ReadFile(path)\n\tif err != nil {\n\t\treturn nil, err\n\t}\n\treturn parser.ParseFile(pass.Fset, path, content, 0)\n}\n\nfunc isErrNilCheck(expr ast.Expr) bool {\n\tbin, ok := expr.(*ast.BinaryExpr)\n\tif !ok || (bin.Op != token.NEQ && bin.Op != token.EQL) {\n\t\treturn false\n\t}\n\tleft, lok := bin.X.(*ast.Ident)\n\tright, rok := bin.Y.(*ast.Ident)\n\treturn (lok && left.Name == \"err\" && rok && right.Name == \"nil\") || (rok && right.Name == \"err\" && lok && left.Name == \"nil\")\n}\n",
